import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  SearchTextInput,
  Modal, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import {
  companyService,
  type CompanyItem,
  type CreateCompanyRequest,
  type UpdateCompanyRequest,
} from '../../../services/company/companyService';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { matchesCodeOrName, normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogFormFooter,
  useCatalogPagination,
  useCatalogTableBusy,
  CatalogListGrid,
  CatalogListMasterLinPageLayout,
  CatalogListHeaderFilters,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-don-vi-co-so';

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

type FormErrors = Partial<Record<'code' | 'name' | 'email', string>>;

const emptyForm = (): Partial<CompanyItem> => ({ isActive: true });

const DonViCoSoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<CompanyItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<CompanyItem | null>(null);
  const [form, setForm] = useState<Partial<CompanyItem>>(emptyForm());
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [detailLoading, setDetailLoading] = useState(false);
  const [togglingId, setTogglingId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const initFormName = editing ? 'edit-company' : 'create-company';
  const { activeStatusOptions } = useVoucherInitData(initFormName);
  const statusActiveLabel = useMemo(
    () => activeStatusOptions.find(o => o.value === 'true')?.label ?? 'Hoạt động',
    [activeStatusOptions],
  );
  const statusInactiveLabel = useMemo(
    () => activeStatusOptions.find(o => o.value === 'false')?.label ?? 'Ngưng',
    [activeStatusOptions],
  );
  const footerActiveLabel = useMemo(
    () => activeStatusOptions.find(o => o.value === 'true')?.label ?? 'Đang hoạt động',
    [activeStatusOptions],
  );

  const filtered = useMemo(() => {
    const q = search.trim();
    if (!q) return items;
    return items.filter(r => matchesCodeOrName(r.code, r.name, q, r.shortName));
  }, [items, search]);

  const { page, setPage, pageItems, totalCount, pageSize, setPageSize, resetPage } = useCatalogPagination(filtered);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useCatalogListSelection({
    rows: pageItems,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };
  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      companyService
        .getAll()
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: err instanceof Error ? err.message : 'Lỗi tải danh sách đơn vị cơ sở',
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã đơn vị';
    if (!form.name?.trim()) next.name = 'Nhập tên đơn vị';
    const email = form.email?.trim();
    if (email && !EMAIL_RE.test(email)) next.email = 'Email không hợp lệ';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setEditing(null);
    setForm(emptyForm());
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = async (row: CompanyItem) => {
    setEditing(row);
    setErrors({});
    markClean();
    setModalOpen(true);
    setDetailLoading(true);
    try {
      const detail = await companyService.getById(row.id);
      setForm({ ...detail });
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Lỗi tải chi tiết đơn vị',
        type: 'error',
      });
      setForm({ ...row });
    } finally {
      setDetailLoading(false);
    }
  };

  const trimOptional = (v?: string) => {
    const s = v?.trim();
    return s || undefined;
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        const payload: UpdateCompanyRequest = {
          name: form.name!.trim(),
          shortName: trimOptional(form.shortName),
          logoUrl: trimOptional(form.logoUrl),
          address: trimOptional(form.address),
          phone: trimOptional(form.phone),
          email: trimOptional(form.email),
          isActive: form.isActive ?? true,
        };
        await companyService.update(editing.id, payload);
      } else {
        const payload: CreateCompanyRequest = {
          code: normalizeCode(form.code!),
          name: form.name!.trim(),
          shortName: trimOptional(form.shortName),
          logoUrl: trimOptional(form.logoUrl),
          address: trimOptional(form.address),
          phone: trimOptional(form.phone),
          email: trimOptional(form.email),
          isActive: form.isActive ?? true,
        };
        await companyService.create(payload);
      }
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật đơn vị cơ sở thành công' : 'Tạo đơn vị cơ sở thành công',
        type: 'success',
      });
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleToggleStatus = async (row: CompanyItem) => {
    setTogglingId(row.id);
    try {
      const updated = await companyService.toggleStatus(row.id);
      setItems(prev => prev.map(i => (i.id === row.id ? { ...i, isActive: updated.isActive } : i)));
      dispatchAppToast(dispatch, { message: 'Đã đổi trạng thái đơn vị cơ sở', type: 'success' });
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: err instanceof Error ? err.message : 'Đổi trạng thái thất bại',
        type: 'error',
      });
    } finally {
      setTogglingId(null);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? filtered.map(r => r.id)
        : [...selection.selectedIds].filter(id => filtered.some(r => r.id === id));
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(async id => {
        const row = items.find(r => r.id === id)!;
        await companyService.update(id, {
          name: row.name,
          shortName: row.shortName,
          logoUrl: row.logoUrl,
          address: row.address,
          phone: row.phone,
          email: row.email,
          isActive: false,
        });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} đơn vị cơ sở`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => companyService.delete(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} đơn vị cơ sở`, type: 'success' });
    }
    refresh();
  };

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={pageItems}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setPage(p); selection.clearSelection(); }}
        onPageSizeChange={setPageSize}
        showTableLoading={showTableLoading}
        header={{
          title: 'Danh mục đơn vị cơ sở',
          titleIconClass: 'fas fa-building',
          subTitle: 'Quản lý công ty / tenant (multi-company)',
        }}
        listTitle="Danh sách đơn vị cơ sở"
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên, tên viết tắt..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </div>
          </CatalogListHeaderFilters>
        )}
        extraModals={<LeaveConfirmModal {...leaveConfirmModalProps} />}
      >
        {filtered.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy đơn vị phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={pageItems}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.id}
            headerCells={(
              <>
                <th>Mã</th>
                <th>Tên</th>
                <th>Tên viết tắt</th>
                <th>Trạng thái</th>
              </>
            )}
            renderRow={r => (
              <>
                <td><code>{r.code}</code></td>
                <td>{r.name}</td>
                <td>{r.shortName ?? '—'}</td>
                <td>
                  <button
                    type="button"
                    className={`${styles.statusToggle} ${r.isActive ? styles.tagSuccess : styles.tagDefault}`}
                    title="Đổi trạng thái"
                    disabled={togglingId === r.id}
                    data-testid={`${TEST_ID}-toggle-status-${r.id}`}
                    onClick={() => handleToggleStatus(r)}
                  >
                    {togglingId === r.id ? (
                      <i className="fas fa-spinner fa-spin" />
                    ) : (
                      r.isActive ? statusActiveLabel : statusInactiveLabel
                    )}
                  </button>
                </td>
              </>
            )}
          />
        )}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={editing ? 'Sửa đơn vị cơ sở' : 'Thêm đơn vị cơ sở'}
        size="md"
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          {detailLoading ? (
            <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
          ) : (
            <div className={styles.formGrid}>
              <div className={styles.masterCodeNameRow}>
                <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                  <label className={styles.label}>Mã đơn vị *</label>
                  <Input
                    value={form.code ?? ''}
                    disabled={!!editing}
                    error={errors.code}
                    className={styles.codeInput}
                    onChange={e => {
                      markDirty();
                      clearFieldError('code');
                      setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                    }}
                  />
                </div>
                <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                  <label className={styles.label}>Tên đơn vị *</label>
                  <Input
                    value={form.name ?? ''}
                    error={errors.name}
                    onChange={e => {
                      markDirty();
                      clearFieldError('name');
                      setForm(f => ({ ...f, name: e.target.value }));
                    }}
                  />
                </div>
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-shortName`}>
                <label className={styles.label}>Tên viết tắt</label>
                <Input
                  value={form.shortName ?? ''}
                  onChange={e => {
                    markDirty();
                    setForm(f => ({ ...f, shortName: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-logoUrl`}>
                <label className={styles.label}>Logo (URL)</label>
                <Input
                  value={form.logoUrl ?? ''}
                  placeholder="https://..."
                  onChange={e => {
                    markDirty();
                    setForm(f => ({ ...f, logoUrl: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-address`}>
                <label className={styles.label}>Địa chỉ</label>
                <Input
                  value={form.address ?? ''}
                  onChange={e => {
                    markDirty();
                    setForm(f => ({ ...f, address: e.target.value }));
                  }}
                />
              </div>
              <div className={styles.masterCodeNameRow}>
                <div className={styles.field} data-testid={`${TEST_ID}-field-phone`}>
                  <label className={styles.label}>Điện thoại</label>
                  <Input
                    value={form.phone ?? ''}
                    onChange={e => {
                      markDirty();
                      setForm(f => ({ ...f, phone: e.target.value }));
                    }}
                  />
                </div>
                <div className={styles.field} data-testid={`${TEST_ID}-field-email`}>
                  <label className={styles.label}>Email</label>
                  <Input
                    value={form.email ?? ''}
                    error={errors.email}
                    onChange={e => {
                      markDirty();
                      clearFieldError('email');
                      setForm(f => ({ ...f, email: e.target.value }));
                    }}
                  />
                </div>
              </div>
            </div>
          )}
          <CatalogFormFooter
            testIdPrefix={TEST_ID}
            hideCompanyField
            checked={form.isActive ?? true}
            activeLabel={footerActiveLabel}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            activeDisabled={detailLoading}
            saveDisabled={detailLoading}
          />
        </div>
      </Modal>
    </>
  );
};

export default DonViCoSoPage;
